	var vis = vector<bool>(n + m + 1);
	ll a = 0, b = 0, c = 0;
	fa(k, 1, n) {
		if (vis[A[k]])continue;
		fa(i, 1, n + m) {
			if (i * A[k] > n + m)break;
			vis[i * A[k]] = 1;
		}
	}
